                result += this.escape(value.slice(cursor, idx));
            const matched = this.escape(value.slice(idx, idx + query.length));
            result += `<mark class="ds-highlight">${matched}</mark>`;
            cursor = idx + query.length;
        }
        return this.sanitizer.bypassSecurityTrustHtml(result);
    }
    escape(s) {
        return s
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#039;');
